package kotlinx.coroutines.exceptions

import kotlinx.coroutines.*
import org.junit.Test
import kotlin.test.*

class NestedExceptionTest : TestBase() {

    @Test
    fun testNestedException() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")

        // If the bug is present, ex.cause will be NestedException instead of IllegalStateException
        // because recoverStackTrace will have created a new NestedException(cause = originalNestedException)
        // using the wrong constructor or wrong arguments.

        assertTrue(ex is NestedException, "Expected NestedException, but was ${ex::class}")
        if (ex.cause is NestedException) {
            val nestedEx = ex.cause as NestedException
            fail("StackTraceRecovery nested the exception: ex.cause is NestedException, which has cause ${nestedEx.cause}")
        }
        assertTrue(ex.cause is IllegalStateException, "Expected cause to be IllegalStateException, but was ${ex.cause?.let { it::class }}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }
}

class NestedException : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}
