 49→private fun createSafeConstructor(constructor: Constructor<*>): Ctor? {
 50→    val p = constructor.parameterTypes
 51→    return when (p.size) {
 52→        2 -> when {
 53→            p[0] == String::class.java && p[1] == Throwable::class.java ->
 54→                safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
 55→            else -> null
 56→        }
 57→        1 -> when (p[0]) {
 58→            Throwable::class.java ->
 59→                safeCtor { e -> constructor.newInstance(e) as Throwable }
 60→            String::class.java ->
 61→                safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
 62→            else -> null
 63→        }
 64→        0 -> safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
 65→        else -> null
