class NestedException : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}

fun main() {
    val constructors = NestedException::class.java.constructors
    println("NestedException constructors:")
    constructors.forEach { println(it) }

    val sorted = constructors.sortedByDescending { it.parameterTypes.size }
    println("Sorted NestedException constructors:")
    sorted.forEach { println(it) }
}
"}

